class FreqStack:
    def __init__(self):
        self.freq_dict = {}

    def push(self, val: int):
        if val not in self.freq_dict:
            self.freq_dict[val] = 1
        else:
            self.freq_dict[val] += 1

    def pop(self):
        if len(self.freq_dict) == 0:
            raise Exception("Stack underflow")

        max_freq = max(self.freq_dict.values())
        max_key = None
        for key, freq in self.freq_dict.items():
            if freq == max_freq:
                max_key = key
                if len(self.freq_dict) == 1:
                    raise Exception("Stack underflow")
                self.freq_dict.pop(key)
        return max_key

